package liste;import java.sql.SQLOutput;public class List {    private Knoten top = null;    private int position = 0;    public void add(String value, int priority) throws NullPointerException, IllegalArgumentException {        if (value == null) {            throw new NullPointerException("value darf nicht null sein!");        }        if (value.equals("")) {            throw new IllegalArgumentException("Du hast vergessen einen Wert zu schreiben");        }        if (priority < 1 || priority > 3) {            throw new IllegalArgumentException("Die Priorität darf nicht über 3 und unter 1 liegen!");        }        Knoten todo = new Knoten(value, priority);        if (top == null) {            top = todo;            position++;            top.setCounter(position);        } else {            todo.right = top;            top.left = todo;            top = todo;            position++;            top.setCounter(position);        }    }    public void add(Knoten todo) throws NullPointerException, IllegalArgumentException {        if (todo.getValue() == null) {            throw new NullPointerException("value darf nicht null sein!");        }        if (todo.getValue().equals("")) {            throw new IllegalArgumentException("Du hast vergessen einen Wert zu schreiben");        }        if (todo.getPriority() < 1 || todo.getPriority() > 3) {            throw new IllegalArgumentException("Die Priorität darf nicht über 3 und unter 1 liegen!");        }        if (top == null) {            top = todo;            position++;            top.setCounter(position);        } else {            todo.right = top;            top.left = todo;            top = todo;            position++;            top.setCounter(position);        }    }    public void sortPositionPriority() throws NullPointerException {        Knoten sky = top;        Knoten sky2 = top;        if(sky.right == null || sky == null){            throw new NullPointerException("sky ist null");        }        while (sky.right != null) {            if(sky.getPriority() < sky.right.getPriority()){                sky.right.left = sky.left;                sky.left.right = sky.right;                sky.left = sky.right;                sky.right = sky.left.right;                sky.left.right = sky;                sky.right.left = sky;                sky = top;            }            sky = sky.right;        }        while(sky2 != null){            System.out.println(sky.toString());            sky2 = sky2.right;        }    }    /*        1. Überprüfen ob vor dem ersten zu tauschenden Knoten ein weiterer Knoten steht,        oder ob es da null ist. Je nachdem muss der Knoten vorne eingefügt werden oder die Referenz auf null setzen.        2. sky = top, damit der Zeiger wieder zurück springt        3. Nutze merge sort     */    public int middleList()throws NullPointerException{        if(top == null){            throw new NullPointerException("Die Liste ist noch nicht initialisiert.");        }        Knoten search = top;        int counter = 1f;        while(search.right != null){            counter++;            search = search.right;        }        return counter / 2;    }    public void switching(Knoten first, Knoten second) {        /*        Diese Methode tauscht first mit second.         */        first.right = second.right;        second.right = first;        second.left = first.left;        first.left = second;    }    public void insert(String value, int position) {    }    public Knoten delete(Knoten a) {        return a;    }    public void ausgabe() {            Knoten temp = top;            while(temp != null){                System.out.println(temp.toString());                temp = temp.right;            }        }    }